<template>
  <div id="app">
    <navigation :theme="theme" :current="currTheme" />
    <div id="content">
      <transition name="fade">
      <router-view />
    </transition>
    </div>
    <div id="tip">

    </div>
  </div>
</template>

<script>
import navigation from '@/components/navigation'
import pageTop from '@/components/pageTop'
import Cookies from 'js-cookie';

export default {
  name: 'App',
  components: {
    navigation,
    pageTop
  },
  data () {
    return {
      themeList: ['default', 'dark'],
      currTheme: null
    }
  },
  methods: {
    theme () {
      let c = this.themeList.indexOf(this.currTheme);

      if (c == -1) {
        this.currTheme = this.themeList[1]
      } else {
        this.currTheme = this.themeList[(c + 1) % this.themeList.length]
      }
    }
  },
  created () {
    this.currTheme = Cookies.get('theme')
    if (this.currTheme) {
      document.getElementsByTagName("body")[0].className = this.currTheme;
      Cookies.set('theme', this.currTheme, {expires: 90})
    }
  },
  watch: {
    'currTheme': function (n) {
      this.currTheme = n
      document.getElementsByTagName("body")[0].className = this.currTheme
      Cookies.set('theme', this.currTheme, {expires: 90})
    }
  }
}
</script>
<style>@import 'assets/style.css';</style>


