import Vue from 'vue'
import Router from 'vue-router'
import index from '@/components/index'
import comm from '@/components/comm'
import mainGallery from '@/components/mainGallery'
import code from '@/components/code'
import social from '@/components/social'
import notFound from '@/components/notFound'

Vue.use(Router)

export default new Router({
  mode: 'history',
  routes: [
    {
      path: '/',
      name: 'index',
      component: index
    },
    {
      path: '/comm',
      name: 'comm',
      component: comm
    },
    {
      path: '/gallery',
      name: 'gallery',
      component: mainGallery
    },
    {
      path: '/code',
      name: 'code',
      component: code
    },
    {
      path: '/social',
      name: 'social',
      component: social
    },
    { path: '/scripts.html', redirect: {name: 'code'}},
    { path: '/comm.html', redirect: {name: 'comm'}},
    { path: '/gallery.html', redirect: {name: 'gallery'}},
    { path: '/sites.html', redirect: {name: 'social'}},
    { path: '/*', component: notFound }
  ]
})



