<template>
  <div :class="{'image': true, 'hide': thumb == null}" v-on:click="control.set(info)" v-tip="info.file">
    <div class="loader"><ico icon="spinner" pulse /></div>
    <img :src="( thumb || 'https://placehold.it/50' )" :id="'img' + info.file " />
  </div>
</template>

<script>

export default {
  name: 'galleryItem',
  props: ['info', 'control'],
  data () {
    let x = this
    return {
      thumb: x.info.thumb
    }
  },
  methods: {
    crop () {
        let img = this.info
        let image = new Image()
        image.onload = () => {
          let param = (img.param || {size: 100, x: 0, y: 0})
          let thumb = (function (img, param) {
          var res = document.createElement('canvas')
          res.width = param.size
          res.height = param.size

          var old = document.createElement('canvas')
          old.width = img.width
          old.height = img.height
          old.getContext('2d').drawImage(img, 0, 0)

          res.getContext('2d').drawImage(old, param.x, param.y, param.size, param.size, 0, 0, param.size, param.size)
          return res.toDataURL()
          })(image, param)
          this.thumb = thumb
            return thumb
          }
          image.src = img.src
    }
  },
  watch: {
    'info': {
      deep: true,
      handler (n, o) {
        this.crop()
      }
    }
  },
  created () {
    this.thumb = this.info.thumb;
    this.info.src = 'static/gallery/' + this.info.file + '.png'
    this.crop();
  }
}
</script>


