<template>
  <div class="gallery">
    
    <table class="gallery-nav">
      <div class="tab-indicator" :style="currTab"></div>
      <tr>
        <td :class="{'gallery-tab': true, 'active': currGroup === -1}" v-if="items.length > 1" :key="'tab-all'" v-on:click="toPage(-1)">
          All
        </td>
        <td :class="{'gallery-tab': true, 'active': currGroup === id}" v-for="(gal, id) in items" :key="'tab-' + gal.group"  v-on:click="toPage(id)">
          {{ gal.group }}
        </td>
      </tr>
    </table>
    <transition-group class="gallery-disp" tag="div" name="gallery">
      <template v-for="(gal, id) in items" >
        <h3 v-if="currGroup === -1" :key="'h' + id" class="gallery-item">
          {{ gal.group }}
        </h3>
        <div class="gallery-group gallery-item" v-if="(currGroup == id) || (currGroup == -1 )" :key="id">
          <gallery-item
            v-for="img in gal.set"
            :key="gal.group + img.file"
            :info="img"
            :control="control()"
          />
        </div>
      </template>
    </transition-group>

    <modal :name="'gallery-modal'" :content="currItem" :control="control()">
        <img :src="((currItem) ? currItem.src : '')">
        <blockquote v-html="((currItem) ? currItem.desc : '')"></blockquote>
    </modal>
  </div>
</template>

<script>
import galleryItem from "@/components/galleryItem"
import modal from '@/components/modal'

export default {
  name: 'gallery',
  props: ["items"],
  components: { galleryItem, modal },
  data () {
    return {
      currGroup: 0,
      currItem: null
    }
  },
  computed: {
    currTab () {
    let items = this.items
    let currGroup = this.currGroup

    return {
        width: 'calc(100% / ' + ((items.length) > 1 ? items.length + 1 : 1) + ')',
        left: 'calc('+ ((items.length > 1) ? currGroup + 1 : currGroup) + '* 100% / ' + ((items.length > 1) ? items.length + 1 : 1) + ')',
        opacity: ((items.length == 1) ? 0 : 1)
      }
    }
  },
  methods: {
    control () {
      let x = this

      return {
        set: (val) => {x.currItem = val},
        unset: () => {x.currItem = null}
      }
    },
    toPage (n) {this.currGroup = n}
  },
  created () {
    if (this.items.length > 1) {this.currGroup = -1}
    else {this.currGroup = 0}
  }
}
</script>


