<template>
  <section id="index">
    Hello, I'm <b>cae</b>. I like to draw, code, and sleep.
    <br><br>
    This is my personal/portfolio site. I'll keep it up-to-date to the best of my ability.
    <br><br>
    You can hit the star to toggle a night theme.
  </section>
</template>

<script>
export default {
  name: 'index',
  created () {
    if (this.$route.query.page) {
      this.$router.replace({ path: `/${this.$route.query.page}` })
    }
  }
}
</script>



