// The Vue build version to load with the `import` command
// (runtime-only or standalone) has been set in webpack.base.conf with an alias.
import Vue from 'vue'
import App from './App'
import router from './router'
import fontawesome from '@fortawesome/fontawesome'
import { FontAwesomeIcon } from '@fortawesome/vue-fontawesome'
import { faTimes, faStar, faCoffee, faQuestionCircle, faHome, faImages } from '@fortawesome/fontawesome-pro-solid'
import brands from '@fortawesome/fontawesome-free-brands'

Vue.component('ico', FontAwesomeIcon)
fontawesome.library.add(brands, faTimes, faStar, faCoffee, faQuestionCircle, faImages, faHome)

Vue.config.productionTip = false

Vue.directive('tip', {
  inserted (el, binding) {
    el.onmouseover = function (e) {
      let x = (window.Event) ? e.pageX : event.clientX + (document.documentElement.scrollLeft ? document.documentElement.scrollLeft : document.body.scrollLeft),
        y = (window.Event) ? e.pageY : event.clientY + (document.documentElement.scrollTop ? document.documentElement.scrollTop : document.body.scrollTop),
        tip = document.getElementById('tip')
      
      tip.innerText = binding.value
      tip.className = 'active'
      if (tip.getBoundingClientRect().width > (window.innerWidth - x))
        tip.style.left = (x -(tip.getBoundingClientRect().width + 30)) + 'px'
      else tip.style.left = x + 'px'
      tip.style.top = y + 'px'
    };

    el.onmousemove = function (e) {
      let x = (window.Event) ? e.pageX : event.clientX + (document.documentElement.scrollLeft ? document.documentElement.scrollLeft : document.body.scrollLeft),
        y = (window.Event) ? e.pageY : event.clientY + (document.documentElement.scrollTop ? document.documentElement.scrollTop : document.body.scrollTop),
      tip = document.getElementById('tip')
      
      if (tip.getBoundingClientRect().width > (window.innerWidth - x))
        tip.style.left = (x - (tip.getBoundingClientRect().width + 30)) + 'px'
      else tip.style.left = x + 'px'
      tip.style.top = y + 'px'
    };

    el.onmouseleave = function () {
      tip.className = ''
      tip.innerText = ''
    }
  }
})
/* eslint-disable no-new */
new Vue({
  el: '#app',
  router,
  components: { App },
  template: '<App/>'
})



